class OAuthClient {
  constructor(config) {
    this.clientId = config.clientId;
    this.authorizationEndpoint = config.authorizationEndpoint;
    this.redirectUri = config.redirectUri;
    this.scopes = config.scopes || 'openid';
    this.token = null;
    this.tokenExpiry = null;
  }

  async authorize() {
    const url = new URL(this.authorizationEndpoint);
    url.searchParams.append('response_type', 'token');
    url.searchParams.append('client_id', this.clientId);
    url.searchParams.append('redirect_uri', this.redirectUri);
    url.searchParams.append('scope', this.scopes);
    url.searchParams.append('state', this.generateState());

    window.location.href = url.toString();
  }

  parseTokenFromFragment() {
    const fragment = window.location.hash.substring(1);
    const params = new URLSearchParams(fragment);
    
    const accessToken = params.get('access_token');
    const expiresIn = params.get('expires_in');
    const tokenType = params.get('token_type');
    const state = params.get('state');

    if (accessToken) {
      this.token = accessToken;
      this.tokenType = tokenType;
      
      if (expiresIn) {
        this.tokenExpiry = Date.now() + (parseInt(expiresIn) * 1000);
      }

      // Remove token from URL
      window.history.replaceState({}, document.title, window.location.pathname);
      
      return true;
    }
    
    return false;
  }

  generateState() {
    return Math.random().toString(36).substring(2, 15) + 
           Math.random().toString(36).substring(2, 15);
  }

  isAuthenticated() {
    return this.token !== null && 
           (!this.tokenExpiry || Date.now() < this.tokenExpiry);
  }

  async makeAuthenticatedRequest(url, options = {}) {
    if (!this.isAuthenticated()) {
      throw new Error('No valid access token available');
    }

    const headers = {
      'Authorization': `${this.tokenType || 'Bearer'} ${this.token}`,
      ...options.headers
    };

    return fetch(url, {
      ...options,
      headers
    });
  }

  clearToken() {
    this.token = null;
    this.tokenExpiry = null;
  }

  async handleCallback() {
    if (window.location.hash.includes('access_token')) {
      const tokenParsed = this.parseTokenFromFragment();
      if (tokenParsed) {
        return true;
      }
    }
    return false;
  }
}

